import { useEffect, useState } from "react";

const SIZE = 10;

function point(x, y) {
  return { x, y };
}

function add(a, b) {
  return point(a.x + b.x, a.y + b.y);
}

function equal(a, b) {
  return a.x === b.x && a.y === b.y;
}

function randomFood() {
  return point(
    Math.floor(Math.random() * SIZE),
    Math.floor(Math.random() * SIZE)
  );
}

function progress(snake, food, direction) {
  const head = add(snake[0], direction);

  const nextSnake = [
    head,
    ...snake,
  ];

  if (equal(head, food)) {
    return {
      snake: nextSnake,
      food: randomFood(),
    };
  }

  nextSnake.pop();

  return {
    snake: nextSnake,
    food,
  };
}

export default function Snake() {
  const [snake, setSnake] = useState([
    point(5, 5),
  ]);

  const [food, setFood] = useState(
    point(2, 2)
  );

  const [direction, setDirection] = useState(
    point(1, 0)
  );

  useEffect(() => {
    const timer = setInterval(() => {
      const next = progress(
        snake,
        food,
        direction
      );

      setSnake(next.snake);
      setFood(next.food);
    }, 300);

    return () => clearInterval(timer);
  }, [snake, food, direction]);

  function keyDown(e) {
    if (e.key === "ArrowUp") {
      setDirection(point(0, -1));
    }

    if (e.key === "ArrowDown") {
      setDirection(point(0, 1));
    }

    if (e.key === "ArrowLeft") {
      setDirection(point(-1, 0));
    }

    if (e.key === "ArrowRight") {
      setDirection(point(1, 0));
    }
  }

  function isSnake(cell) {
    return snake.some(part => equal(part, cell));
  }

  function color(cell) {
    if (isSnake(cell)) return "green";
    if (equal(food, cell)) return "red";

    return "white";
  }

  return (
    <main onKeyDown={keyDown} tabIndex={0}>
      <h1>🐍 Snake</h1>

      <table>
        <tbody>
          {Array.from({ length: SIZE }, (_, y) => (
            <tr key={y}>
              {Array.from({ length: SIZE }, (_, x) => {
                const cell = point(x, y);

                return (
                  <td
                    key={x}
                    style={{
                      width: 25,
                      height: 25,
                      border: "1px solid",
                      background: color(cell),
                    }}
                  />
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
